var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，他是必不可少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼とともにいることを。","ENG":"that you'll be with him, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和他一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called him to your office. He said he'd be here soon.","TWN":"做好心理準備後，你將他傳喚到老闆辦公室，他說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"내가 제일 싫어하는 소리는 가족 같은 회사요.","JPN":"家族のような会社……私のもっとも苦手とするフレーズです。","ENG":"The thing that I hate the most is a company that's like a family.","TWN":"我最討厭別人說公司像家一樣。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"회사라는 건, 각자 자기 일만 열심히 해도 돌아가게 되어 있어.","JPN":"会社というものは、それぞれが己の仕事を全うしていれば回っていくものです。","ENG":"A company is just a group of strangers doing what they can do to keep it running.","TWN":"公司這種地方，就算每個人只努力做自己的工作，也能正常運轉。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"직원은 맡은 일 열심히 하고, 관리직은 일이 제대로 돌아가게 하고, 윗분들께선 일할 환경 깔아 주고.","JPN":"社員は任せられた仕事を全うし、管理職は仕事が滞りなく進むようにし、上層部は働くための環境を整えてくれればいい。","ENG":"The employees are to do what they're told; the managers, to manage them; the upper management, to ensure a workable environment.","TWN":"員工認真完成被交代的工作，管理層讓公司正常運轉，主管們則創造良好的工作環境。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"괜히 사족 붙이는 회사치고 제대로 굴러가는 데는 못 봤수다.","JPN":"余計な美辞麗句をつけ加える会社ほど、上手く回らなくなるものです。","ENG":"Any company that expects them to do more than that never lasts long.","TWN":"無緣無故，在沒必要的地方畫蛇添足的公司，是不可能正常運轉的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"그래서 사장님이 마음에 듭니다. 일하는 대로 수당 꼬박꼬박 챙겨 주고, 젊은 애들 등쳐 먹을 생각은 없어 보이니까.","JPN":"しかし、社長のことは気に入ってますよ。働いた分だけ手当てを付けてくれますし、若者を食い物にするつもりもなさそうですからね。","ENG":"That's why I like you, Boss. You pay your employees what they deserve, and you don't exploit inexperienced youngsters, either.","TWN":"所以我很喜歡老闆，因為老闆做多少就給多少，看起來也不像是會騙小孩的人。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"나 원, 세상이 이 꼴이니 당연한 얘기도 칭찬처럼 되버리는군.","JPN":"やれやれ、まったく世も末です。こんな当たり前すぎることが、賞賛に値することになってしまうとは。","ENG":"Geez, the world is so messed up that things that should be normal have become praiseworthy.","TWN":"我的天，因為這世道長這副德行，所以理所當然的話都變得像在讚美一樣，"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"아무튼, 종신 계약이라고 하셨지.","JPN":"とにかく、終身契約と言いましたね？","ENG":"Anyway, a lifetime contract, you say?","TWN":"總之，您說終身契約是吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"지금까지처럼, 잘 부탁하겠수다.","JPN":"今まで通り、よろしくお願いしますよ。","ENG":"I promise I'll work as hard as I always have.","TWN":"那麼一如既往，請您多多指教了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};